1	/**
2	 * SKF Installer UI - Banner, prompts, and success message.
3	 * Uses @clack/prompts for terminal UI.
4	 *
5	 * Brand palette (from skf-logo.svg):
6	 *   amber  #F59E0B  — primary (anvil top)
7	 *   gold   #FBBF24  — accent, highlights (anvil horn)
8	 *   dark   #D97706  — frame, deep emphasis (anvil body)
9	 *   spark  #FCD34D  — sparks, icons
10	 */
11	
12	const { intro, outro, text, select, multiselect, confirm, note, isCancel, cancel, log } = require('@clack/prompts');
13	const chalk = require('chalk');
14	const figlet = require('figlet');
15	const path = require('node:path');
16	const fs = require('fs-extra');
17	const yaml = require('js-yaml');
18	const { readManifest } = require('./manifest');
19	const { compareVersions } = require('./version-check');
20	
21	const SKF_FOLDER = '_bmad/skf';
22	
23	// Brand colors derived from skf-logo.svg
24	const brand = {
25	  amber: chalk.hex('#F59E0B'),
26	  gold: chalk.hex('#FBBF24'),
27	  dark: chalk.hex('#D97706'),
28	  spark: chalk.hex('#FCD34D'),
29	};
30	
31	class UI {
32	  displayBanner() {
33	    const packageJson = require('../../../package.json');
34	    const version = packageJson.version;
35	
36	    let logoLines;
37	    try {
38	      logoLines = figlet.textSync('SKF', { font: 'ANSI Shadow' }).trimEnd().split('\n');
39	      // Remove trailing empty lines from figlet output
40	      while (logoLines.length > 0 && !logoLines.at(-1).trim()) logoLines.pop();
41	    } catch {
42	      logoLines = ['  S K F'];
43	    }
44	
45	    const w = 54;
46	    const frame = brand.dark;
47	    const top = frame('  ╔' + '═'.repeat(w) + '╗');
48	    const mid = frame('  ╟' + '─'.repeat(w) + '╢');
49	    const bottom = frame('  ╚' + '═'.repeat(w) + '╝');
50	    const row = (content) => {
51	      // eslint-disable-next-line no-control-regex -- stripping ANSI escape codes for visual width calculation
52	      const stripped = content.replaceAll(/\u001B\[\d+(?:;\d+)*m/g, '');
53	      const pad = Math.max(0, w - stripped.length - 2);
54	      return frame('  ║ ') + content + ' '.repeat(pad) + frame(' ║');
55	    };
56	
57	    console.log();
58	    console.log(top);
59	    for (const line of logoLines) {
60	      console.log(row(brand.amber.bold(line.replace(/\s+$/, ''))));
61	    }
62	    console.log(mid);
63	    console.log(row(chalk.white.bold('Skill Forge') + chalk.dim(` v${version}`)));
64	    console.log(row(chalk.dim('Agent Skill Compiler') + ' '.repeat(15) + brand.spark('⚒')));
65	    console.log(mid);
66	    console.log(row(chalk.dim('Code · Docs · Discourse → Verified agent skills')));
67	    console.log(bottom);
68	    console.log();
69	
70	    intro(brand.amber('Skill Forge Installer'));
71	  }
72	
73	  async detectInstallation(projectDir) {
74	    const hasBmadSkf = await fs.pathExists(path.join(projectDir, SKF_FOLDER));
75	    const hasBmadDir = await fs.pathExists(path.join(projectDir, '_bmad'));
76	
77	    if (hasBmadSkf) {
78	      return { type: 'existing', folder: SKF_FOLDER };
79	    }
80	    if (hasBmadDir) {
81	      return { type: 'bmad-ready', folder: SKF_FOLDER };
82	    }
83	    return { type: 'fresh', folder: SKF_FOLDER };
84	  }
85	
86	  async promptInstall() {
87	    this.displayBanner();
